const event = $input.first().json.events?.[0] || $input.first().json.body?.events?.[0];
const messageText = event?.message?.text || '';
const replyToken = event?.replyToken || '';
const userId = event?.source?.userId || '';

const urlMatch = messageText.match(/(https?:\/\/[^\s]+)/);
const targetUrl = urlMatch ? urlMatch[1] : '';

const ycMatch = targetUrl.match(/([A-Z]{2}\d{6,})/i) || targetUrl.match(/\/(\d+)(?:[\/?#]|$)/);
const caseId = ycMatch ? ycMatch[1].toUpperCase() : '';

if (!targetUrl) {
  throw new Error(`找不到網址。原始訊息：「${messageText}」長度=${messageText.length}`);
}

return [{ json: { targetUrl, caseId, replyToken, userId, rawMessage: messageText } }];

let html = $input.first().json.data || $input.first().json.body || '';
// 砍 script 前先從 JSON-LD 抓真物件編號 productID（例 YC1868705），這才是官網依據，不用網址尾號
const pidMatch = html.match(/"productID"\s*:\s*"([A-Za-z]{2}\d{5,})"/);
const productId = pidMatch ? pidMatch[1].toUpperCase() : '';
// 同樣從 JSON-LD 抓官方開價（offers.price，單位:萬）— 總價是廣告紅線，不能讓 AI 猜
const priceMatch = html.match(/"offers"[\s\S]{0,150}?"price"\s*:\s*"?(\d{2,7})/) || html.match(/"price"\s*:\s*"?(\d{2,7})"?\s*,\s*"priceCurrency"/);
const priceWan = priceMatch ? Number(priceMatch[1]) : null;
html = html.replace(/<script[\s\S]*?<\/script>/gi, '');
html = html.replace(/<style[\s\S]*?<\/style>/gi, '');
html = html.replace(/<!--[\s\S]*?-->/g, '');
html = html.replace(/<noscript[\s\S]*?<\/noscript>/gi, '');
const bodyMatch = html.match(/<body[\s\S]*?<\/body>/i);
let content = bodyMatch ? bodyMatch[0] : html;
content = content.replace(/\s+/g, ' ').trim();
if (content.length > 80000) content = content.substring(0, 80000);
return [{ json: { ...$('解析 LINE 指令').first().json, productId, priceWan, cleanedHtml: content, htmlLength: content.length } }];

const response = $input.first().json;
const aiText = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
let jsonText = aiText.trim().replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/\s*```$/, '');
let parsed;
try { parsed = JSON.parse(jsonText); }
catch (e) { throw new Error('AI 回傳 JSON 解析失敗: ' + e.message + ' 原始: ' + aiText.substring(0, 500)); }
const inputData = $('清理 HTML').first().json;
// 總價鎖成官方開價(priceWan)；並把 AI 文案內若寫錯的開價換成正確值
const priceWan = inputData.priceWan;
let 總價 = String(parsed['總價'] || '').trim();
let copy = String(parsed['產生的文案'] || '');
if (priceWan) {
  const aiNum = (總價.match(/\d{2,7}/) || [])[0];
  if (aiNum && Number(aiNum) !== priceWan) {
    copy = copy.split(aiNum + ' 萬').join(priceWan + ' 萬').split(aiNum + '萬').join(priceWan + '萬');
  }
  總價 = priceWan + ' 萬';
}
return [{ json: { ...parsed, 總價, 產生的文案: copy, targetUrl: inputData.targetUrl, replyToken: inputData.replyToken, userId: inputData.userId, 案件編號: (() => { const raw = String(inputData.productId || parsed.案件編號 || inputData.caseId || '').trim(); if (!raw) return ''; return /^[A-Za-z]{2}\d/.test(raw) ? raw.toUpperCase() : 'YC' + raw; })() } }];

const ai = $('解析 AI 輸出').first().json;
const existing = ($json.results || [])[0] || null;
return [{ json: { ...ai,
  existingPageId: existing?.id || null,
  existingVersion: existing?.properties?.['文案版本']?.number ?? 0,
  action: existing ? '更新' : '建檔'
}}];

const notionPage = $input.first().json;
const aiData = $('解析 AI 輸出').first().json;
const existData = $('取出 existingPageId').first().json;
const action = existData.action || '建檔';
const notionUrl = notionPage.url || `https://www.notion.so/${notionPage.id?.replace(/-/g, '')}`;
const caseName = aiData['案名'] || '未命名物件';
const caseId = aiData['案件編號'] || '無編號';
const totalPrice = aiData['總價'] || '';
const layout = aiData['格局'] || '';
const copy = aiData['產生的文案'] || '';
const replyText = `✅ ${action}完成\n\n📋 ${caseName}\n🏷 ${caseId}　💰 ${totalPrice}　🏠 ${layout}\n\n🔗 ${notionUrl}\n\n━━━ 文案預覽 ━━━\n${copy}`;
return [{ json: { replyToken: aiData.replyToken, replyText, notionUrl, notionPageId: notionPage.id } }];
